// Extrair email que deu bounce do corpo da mensagem
const items = $input.all();
const results = [];

for (const item of items) {
  const text = item.json.textPlain || item.json.snippet || '';

  // Padroes comuns de bounce
  const patterns = [
    /delivery to the following recipient[s]? failed[\s\S]*?([\w.+-]+@[\w.-]+\.[a-z]{2,})/gi,
    /The email account that you tried to reach does not exist[\s\S]*?([\w.+-]+@[\w.-]+\.[a-z]{2,})/gi,
    /Address rejected[\s\S]*?([\w.+-]+@[\w.-]+\.[a-z]{2,})/gi,
    /550[\s-].*?([\w.+-]+@[\w.-]+\.[a-z]{2,})/gi,
    /Undeliverable[\s\S]*?([\w.+-]+@[\w.-]+\.[a-z]{2,})/gi,
    /(?:To|to):\s*<?([\w.+-]+@[\w.-]+\.[a-z]{2,})>?/g
  ];

  let bouncedEmail = null;

  for (const pattern of patterns) {
    const match = pattern.exec(text);
    if (match && match[1]) {
      bouncedEmail = match[1].toLowerCase();
      break;
    }
  }

  // Fallback: pegar do header "To" original da mensagem bounced
  if (!bouncedEmail && item.json.headers) {
    const xFailedTo = item.json.headers['X-Failed-Recipients'];
    if (xFailedTo) {
      bouncedEmail = xFailedTo.toLowerCase().trim();
    }
  }

  if (bouncedEmail) {
    results.push({ json: { email_bounce: bouncedEmail, gmail_id: item.json.id } });
  }
}

return results.length > 0 ? results : [{ json: { email_bounce: null } }];

